1	import { NamedType, namedType, TypeBuilder } from '@prisma/ts-builders'
2	
3	export function omit(type: TypeBuilder, keyType: TypeBuilder): NamedType {
4	  return namedType('Omit').addGenericArgument(type).addGenericArgument(keyType)
5	}
6	
7	export function promise(resultType: TypeBuilder): NamedType {
8	  return new NamedType('runtime.Types.Utils.JsPromise').addGenericArgument(resultType)
9	}
10	
11	export function prismaPromise(resultType: TypeBuilder): NamedType {
12	  return new NamedType('Prisma.PrismaPromise').addGenericArgument(resultType)
13	}
14	
15	export function optional(innerType: TypeBuilder) {
16	  return new NamedType('runtime.Types.Utils.Optional').addGenericArgument(innerType)
