import type { FieldKind } from '@prisma/dmmf'

const scalarMap: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'Date | string',
  Json: 'unknown',
  BigInt: 'bigint | number',
  Decimal: 'number | string',
  Bytes: 'string',
  ID: 'string',
  UUID: 'string',
  Long: 'number',
}

/**
 * Maps a Prisma DMMF field type to a TypeScript type string.
 *
 * Relation fields (`kind === 'object'`) are not expected here — callers
 * should filter them out before calling this function.
 */
export function prismaScalarToTypeScript(type: string, kind: FieldKind, isList: boolean, isRequired: boolean): string {
  let tsType: string

  if (kind === 'enum') {
    tsType = type
  } else if (kind === 'scalar') {
    tsType = scalarMap[type] ?? 'unknown'
  } else {
    tsType = 'unknown'
  }

  if (isList) {
    tsType = `${tsType}[]`
  }

  if (!isRequired && !isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

