/** Generates TypeScript enum declarations from Prisma DMMF enums. */
export function generateEnums(enums: readonly DatamodelEnum[]): string {
  const parts: string[] = []

  parts.push('// Generated by prisma-rest-api generator — do not edit manually\n')

  for (const enumDef of enums) {
    if (enumDef.documentation) {
      parts.push(`/** ${enumDef.documentation} */`)
    }

    const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')

    parts.push(`export enum ${enumDef.name} {\n${members}\n}\n`)
  }

  return parts.join('\n')
}

