import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

import { prismaScalarToTypeScript } from '../type-map'

/** Names of DMMF default functions that indicate auto-generated values. */
const AUTO_DEFAULT_NAMES = new Set(['autoincrement', 'now', 'uuid', 'cuid', 'dbgenerated', 'auto'])

function isAutoGeneratedField(field: Field): boolean {
  if (field.isReadOnly) return true
  if (field.isUpdatedAt) return true
  if (field.isId && field.hasDefaultValue) return true

  if (field.hasDefaultValue && typeof field.default === 'object' && field.default !== null && !Array.isArray(field.default)) {
    const def = field.default as { name?: string }
    if (def.name && AUTO_DEFAULT_NAMES.has(def.name)) return true
  }

  return false
}

function hasSimpleDefault(field: Field): boolean {
  if (!field.hasDefaultValue) return false
  if (typeof field.default === 'object' && field.default !== null && !Array.isArray(field.default)) {
    const def = field.default as { name?: string }
    if (def.name && AUTO_DEFAULT_NAMES.has(def.name)) return false
  }
  return true
}

/** Generates TypeScript interfaces for a single model: the model type, create input, and update input. */
export function generateModelTypes(model: Model, enums: readonly DatamodelEnum[]): string {
  const parts: string[] = []
  const enumNames = new Set(enums.map((e) => e.name))

  const scalarFields = model.fields.filter((f) => f.kind !== 'object')

  // Collect enum imports needed by this model
  const usedEnums = new Set<string>()
  for (const field of scalarFields) {
    if (field.kind === 'enum' && enumNames.has(field.type)) {
      usedEnums.add(field.type)
    }
  }

  parts.push('// Generated by prisma-rest-api generator — do not edit manually\n')

  if (usedEnums.size > 0) {
    const sorted = [...usedEnums].sort()
    parts.push(`import { ${sorted.join(', ')} } from './enums'\n`)
  }

  // --- Model interface ---
  if (model.documentation) {
    parts.push(`/** ${model.documentation} */`)
  }

  const interfaceFields = scalarFields
    .map((f) => {
      const tsType = prismaScalarToTypeScript(f.type, f.kind, f.isList, f.isRequired)
      return `  ${f.name}: ${tsType}`
    })
    .join('\n')

  parts.push(`export interface ${model.name} {\n${interfaceFields}\n}\n`)

  // --- Create input ---
  const createFields = scalarFields.filter((f) => !isAutoGeneratedField(f))
  const createFieldLines = createFields
    .map((f) => {
      const tsType = prismaScalarToTypeScript(f.type, f.kind, f.isList, f.isRequired)
      const optional = !f.isRequired || hasSimpleDefault(f) ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  parts.push(`export interface ${model.name}CreateInput {\n${createFieldLines}\n}\n`)

  // --- Update input ---
  parts.push(`export type ${model.name}UpdateInput = Partial<${model.name}CreateInput>\n`)

  return parts.join('\n')
}

