import type { DatamodelEnum, Model } from '@prisma/dmmf'

import { prismaScalarToTypeScript } from '../type-map'

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

function lowerCase(name: string): string {
  return name.toLowerCase()
}

interface IdField {
  name: string
  tsType: string
}

function getIdFields(model: Model): IdField[] {
  // Composite primary key
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    return model.primaryKey.fields.map((fieldName) => {
      const field = model.fields.find((f) => f.name === fieldName)
      const tsType = field ? prismaScalarToTypeScript(field.type, field.kind, field.isList, field.isRequired) : 'unknown'
      return { name: fieldName, tsType }
    })
  }

  // Single @id field
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return [{ name: idField.name, tsType: prismaScalarToTypeScript(idField.type, idField.kind, idField.isList, idField.isRequired) }]
  }

  return []
}

function buildIdParam(idFields: IdField[]): string {
  if (idFields.length === 0) return ''
  if (idFields.length === 1) return `${idFields[0].name}: ${idFields[0].tsType}`
  const members = idFields.map((f) => `${f.name}: ${f.tsType}`).join('; ')
  return `id: { ${members} }`
}

function buildIdPath(idFields: IdField[], modelPath: string): string {
  if (idFields.length === 1) {
    return `\`${modelPath}/\${${idFields[0].name}}\``
  }
  // For composite keys, encode as query params
  const params = idFields.map((f) => `\${${f.name}}`).join(',')
  return `\`${modelPath}/\${${params}}\``
}

function generateModelMethods(model: Model): string {
  const prefix = camelCase(model.name)
  const route = `/${lowerCase(model.name)}`
  const idFields = getIdFields(model)
  const lines: string[] = []

  // findMany
  lines.push(`  async ${prefix}FindMany(): Promise<${model.name}[]> {`)
  lines.push(`    return this.request<${model.name}[]>('GET', '${route}')`)
  lines.push(`  }\n`)

  if (idFields.length > 0) {
    const idParam = buildIdParam(idFields)

    if (idFields.length === 1) {
      const idName = idFields[0].name
      // findUnique
      lines.push(`  async ${prefix}FindUnique(${idParam}): Promise<${model.name} | null> {`)
      lines.push(`    return this.request<${model.name} | null>('GET', \`${route}/\${${idName}}\`)`)
      lines.push(`  }\n`)

      // create
      lines.push(`  async ${prefix}Create(data: ${model.name}CreateInput): Promise<${model.name}> {`)
      lines.push(`    return this.request<${model.name}>('POST', '${route}', data)`)
      lines.push(`  }\n`)

      // update
      lines.push(`  async ${prefix}Update(${idParam}, data: ${model.name}UpdateInput): Promise<${model.name}> {`)
      lines.push(`    return this.request<${model.name}>('PATCH', \`${route}/\${${idName}}\`, data)`)
      lines.push(`  }\n`)

      // delete
      lines.push(`  async ${prefix}Delete(${idParam}): Promise<${model.name}> {`)
      lines.push(`    return this.request<${model.name}>('DELETE', \`${route}/\${${idName}}\`)`)
      lines.push(`  }`)
    } else {
      // Composite key: destructure from object parameter
      const destructured = idFields.map((f) => f.name).join(', ')
      const queryParts = idFields.map((f) => `\${encodeURIComponent(String(${f.name}))}`).join('/')

      lines.push(`  async ${prefix}FindUnique(${idParam}): Promise<${model.name} | null> {`)
      lines.push(`    const { ${destructured} } = id`)
      lines.push(`    return this.request<${model.name} | null>('GET', \`${route}/\${${queryParts}}\`)`)
      lines.push(`  }\n`)

      lines.push(`  async ${prefix}Create(data: ${model.name}CreateInput): Promise<${model.name}> {`)
      lines.push(`    return this.request<${model.name}>('POST', '${route}', data)`)
      lines.push(`  }\n`)

      lines.push(`  async ${prefix}Update(${idParam}, data: ${model.name}UpdateInput): Promise<${model.name}> {`)
      lines.push(`    const { ${destructured} } = id`)
      lines.push(`    return this.request<${model.name}>('PATCH', \`${route}/\${${queryParts}}\`, data)`)
      lines.push(`  }\n`)

      lines.push(`  async ${prefix}Delete(${idParam}): Promise<${model.name}> {`)
      lines.push(`    const { ${destructured} } = id`)
      lines.push(`    return this.request<${model.name}>('DELETE', \`${route}/\${${queryParts}}\`)`)
      lines.push(`  }`)
    }
  } else {
    // No ID field: only findMany and create are supported
    lines.push(`  async ${prefix}Create(data: ${model.name}CreateInput): Promise<${model.name}> {`)
    lines.push(`    return this.request<${model.name}>('POST', '${route}', data)`)
    lines.push(`  }`)
  }

  return lines.join('\n')
}

/** Generates the RestApiClient class with typed CRUD methods for all models. */
export function generateClientClass(models: readonly Model[], _enums: readonly DatamodelEnum[]): string {
  const parts: string[] = []

  parts.push('// Generated by prisma-rest-api generator — do not edit manually\n')

  // Imports
  for (const model of models) {
    parts.push(
      `import type { ${model.name}, ${model.name}CreateInput, ${model.name}UpdateInput } from './${model.name}'`,
    )
  }

  parts.push('')

  // Config interface
  parts.push(`export interface RestApiClientConfig {`)
  parts.push(`  baseUrl: string`)
  parts.push(`  headers?: Record<string, string>`)
  parts.push(`}\n`)

  // Class
  parts.push(`export class RestApiClient {`)
  parts.push(`  #baseUrl: string`)
  parts.push(`  #headers: Record<string, string>\n`)

  // Constructor
  parts.push(`  constructor(config: RestApiClientConfig) {`)
  parts.push(`    this.#baseUrl = config.baseUrl.replace(/\\/$/, '')`)
  parts.push(`    this.#headers = {`)
  parts.push(`      'Content-Type': 'application/json',`)
  parts.push(`      ...config.headers,`)
  parts.push(`    }`)
  parts.push(`  }\n`)

  // Private request helper
  parts.push(`  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {`)
  parts.push(`    const response = await fetch(\`\${this.#baseUrl}\${path}\`, {`)
  parts.push(`      method,`)
  parts.push(`      headers: this.#headers,`)
  parts.push(`      body: body !== undefined ? JSON.stringify(body) : undefined,`)
  parts.push(`    })`)
  parts.push(`    if (!response.ok) {`)
  parts.push(`      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)`)
  parts.push(`    }`)
  parts.push(`    return response.json() as Promise<T>`)
  parts.push(`  }\n`)

  // Per-model methods — use the private helper via `this.request`
  // (We generate a private wrapper that forwards to #request so the
  //  per-model method generator can reference `this.request` simply.)
  parts.push(`  private async request<T>(method: string, path: string, body?: unknown): Promise<T> {`)
  parts.push(`    return this.#request<T>(method, path, body)`)
  parts.push(`  }\n`)

  for (let i = 0; i < models.length; i++) {
    if (i > 0) parts.push('')
    parts.push(generateModelMethods(models[i]))
  }

  parts.push(`}\n`)

  return parts.join('\n')
}

