/** Generates the barrel index.ts that re-exports all generated types and the client. */
export function generateIndex(models: readonly Model[], enums: readonly DatamodelEnum[]): string {
  const parts: string[] = []

  parts.push('// Generated by prisma-rest-api generator — do not edit manually\n')

  if (enums.length > 0) {
    parts.push(`export * from './enums'`)
  }

  for (const model of models) {
    parts.push(`export * from './${model.name}'`)
  }

  parts.push(`export * from './client'`)
  parts.push('')

  return parts.join('\n')
}

