import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-rest-client'

/**
 * Prisma generator that outputs a typed REST API client with per-model
 * CRUD methods (`findMany`, `findUnique`, `create`, `update`, `delete`).
 */
export class PrismaRestApiGenerator implements Generator {
  readonly name = 'prisma-rest-api'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated/rest-client',
      prettyName: 'Prisma REST API Client',
      requiresEngines: [],
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error('An output path is required for the `prisma-rest-api` generator.')
    }

    await generateRestClient({
      dmmf: options.dmmf,
      outputDir,
    })
  }
}

