import { describe, expect, test } from 'vitest'

import { prismaScalarToTypeScript } from '../type-map'

describe('prismaScalarToTypeScript', () => {
  test('maps String to string', () => {
    expect(prismaScalarToTypeScript('String', 'scalar', false, true)).toBe('string')
  })

  test('maps Int to number', () => {
    expect(prismaScalarToTypeScript('Int', 'scalar', false, true)).toBe('number')
  })

  test('maps Float to number', () => {
    expect(prismaScalarToTypeScript('Float', 'scalar', false, true)).toBe('number')
  })

  test('maps Boolean to boolean', () => {
    expect(prismaScalarToTypeScript('Boolean', 'scalar', false, true)).toBe('boolean')
  })

  test('maps DateTime to Date | string', () => {
    expect(prismaScalarToTypeScript('DateTime', 'scalar', false, true)).toBe('Date | string')
  })

  test('maps BigInt to bigint | number', () => {
    expect(prismaScalarToTypeScript('BigInt', 'scalar', false, true)).toBe('bigint | number')
  })

  test('maps Decimal to number | string', () => {
    expect(prismaScalarToTypeScript('Decimal', 'scalar', false, true)).toBe('number | string')
  })

  test('maps Json to unknown', () => {
    expect(prismaScalarToTypeScript('Json', 'scalar', false, true)).toBe('unknown')
  })

  test('maps Bytes to string', () => {
    expect(prismaScalarToTypeScript('Bytes', 'scalar', false, true)).toBe('string')
  })

  test('maps unknown types to unknown', () => {
    expect(prismaScalarToTypeScript('SomeUnknownType', 'scalar', false, true)).toBe('unknown')
  })

  test('adds [] for list types', () => {
    expect(prismaScalarToTypeScript('String', 'scalar', true, true)).toBe('string[]')
  })

  test('adds | null for optional non-list types', () => {
    expect(prismaScalarToTypeScript('String', 'scalar', false, false)).toBe('string | null')
  })

  test('list types are not nullable even when not required', () => {
    expect(prismaScalarToTypeScript('String', 'scalar', true, false)).toBe('string[]')
  })

  test('enum types use the enum name directly', () => {
    expect(prismaScalarToTypeScript('UserRole', 'enum', false, true)).toBe('UserRole')
  })

  test('nullable enum types', () => {
    expect(prismaScalarToTypeScript('UserRole', 'enum', false, false)).toBe('UserRole | null')
  })

  test('list enum types', () => {
    expect(prismaScalarToTypeScript('UserRole', 'enum', true, true)).toBe('UserRole[]')
  })

  test('unsupported kinds map to unknown', () => {
    expect(prismaScalarToTypeScript('SomeType', 'unsupported', false, true)).toBe('unknown')
  })
})

