import { describe, expect, test } from 'vitest'

import { generateEnums } from '../generators/generate-enums'

describe('generateEnums', () => {
  test('generates a simple enum', () => {
    const result = generateEnums([
      {
        name: 'UserRole',
        values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
      },
    ])

    expect(result).toContain('export enum UserRole {')
    expect(result).toContain("  ADMIN = 'ADMIN',")
    expect(result).toContain("  USER = 'USER',")
  })

  test('generates multiple enums', () => {
    const result = generateEnums([
      {
        name: 'UserRole',
        values: [{ name: 'ADMIN', dbName: null }],
      },
      {
        name: 'Status',
        values: [{ name: 'ACTIVE', dbName: null }, { name: 'INACTIVE', dbName: null }],
      },
    ])

    expect(result).toContain('export enum UserRole {')
    expect(result).toContain('export enum Status {')
    expect(result).toContain("  ACTIVE = 'ACTIVE',")
    expect(result).toContain("  INACTIVE = 'INACTIVE',")
  })

  test('includes documentation as JSDoc', () => {
    const result = generateEnums([
      {
        name: 'UserRole',
        values: [{ name: 'ADMIN', dbName: null }],
        documentation: 'Roles available for users',
      },
    ])

    expect(result).toContain('/** Roles available for users */')
  })

  test('returns empty-ish output for empty enums array', () => {
    const result = generateEnums([])
    expect(result).not.toContain('export enum')
  })
})

