import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateModelTypes } from '../generators/generate-model-types'

function makeField(overrides: Partial<Field> & { name: string; type: string }): Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: overrides.type,
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

function makeModel(name: string, fields: Field[]): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as Model
}

const emptyEnums: DatamodelEnum[] = []
const roleEnum: DatamodelEnum[] = [{ name: 'UserRole', values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }] }]

describe('generateModelTypes', () => {
  test('generates an interface with scalar fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])

    const result = generateModelTypes(model, emptyEnums)

    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name: string | null')
  })

  test('excludes relation fields (kind === object)', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
      makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true, relationName: 'UserPosts' }),
    ])

    const result = generateModelTypes(model, emptyEnums)

    expect(result).not.toContain('posts')
    expect(result).toContain('  email: string')
  })

  test('omits auto-increment ID from create input', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateModelTypes(model, emptyEnums)

    expect(result).toContain('export interface UserCreateInput {')
    expect(result).not.toMatch(/UserCreateInput[\s\S]*\bid\b/)
    expect(result).toMatch(/UserCreateInput[\s\S]*email: string/)
  })

  test('omits updatedAt fields from create input', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
      makeField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
    ])

    const result = generateModelTypes(model, emptyEnums)
    const createSection = result.slice(result.indexOf('UserCreateInput'))

    expect(createSection).not.toContain('updatedAt')
  })

  test('omits readOnly fields from create input', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'computed', type: 'String', isReadOnly: true }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateModelTypes(model, emptyEnums)
    const createSection = result.slice(result.indexOf('UserCreateInput'))

    expect(createSection).not.toContain('computed')
  })

  test('marks fields with simple defaults as optional in create input', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      makeField({ name: 'email', type: 'String' }),
      makeField({ name: 'published', type: 'Boolean', hasDefaultValue: true, default: false }),
    ])

    const result = generateModelTypes(model, emptyEnums)

    expect(result).toMatch(/published\?: boolean/)
  })

  test('generates update input as Partial<CreateInput>', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateModelTypes(model, emptyEnums)

    expect(result).toContain('export type UserUpdateInput = Partial<UserCreateInput>')
  })

  test('imports enums when model has enum fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'role', type: 'UserRole', kind: 'enum' }),
    ])

    const result = generateModelTypes(model, roleEnum)

    expect(result).toContain("import { UserRole } from './enums'")
    expect(result).toContain('  role: UserRole')
  })

  test('does not import enums when model has no enum fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String' }),
    ])

    const result = generateModelTypes(model, roleEnum)

    expect(result).not.toContain('import')
  })

  test('includes model documentation as JSDoc', () => {
    const model = {
      ...makeModel('User', [makeField({ name: 'id', type: 'Int', isId: true })]),
      documentation: 'A user of the system',
    } as Model

    const result = generateModelTypes(model, emptyEnums)

    expect(result).toContain('/** A user of the system */')
  })
})

