import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateClientClass } from '../generators/generate-client-class'

function makeField(overrides: Partial<Field> & { name: string; type: string }): Field {
  return {
    kind: 'scalar',
    name: overrides.name,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: overrides.type,
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

function makeModel(name: string, fields: Field[]): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as Model
}

const emptyEnums: DatamodelEnum[] = []

describe('generateClientClass', () => {
  test('generates RestApiClient class', () => {
    const models = [
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true }),
        makeField({ name: 'email', type: 'String' }),
      ]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('export interface RestApiClientConfig {')
  })

  test('generates CRUD methods for a model with @id', () => {
    const models = [
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true }),
        makeField({ name: 'email', type: 'String' }),
      ]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain('async userFindMany(): Promise<User[]>')
    expect(result).toContain('async userFindUnique(id: number): Promise<User | null>')
    expect(result).toContain('async userCreate(data: UserCreateInput): Promise<User>')
    expect(result).toContain('async userUpdate(id: number, data: UserUpdateInput): Promise<User>')
    expect(result).toContain('async userDelete(id: number): Promise<User>')
  })

  test('uses correct HTTP methods and paths', () => {
    const models = [
      makeModel('User', [
        makeField({ name: 'id', type: 'Int', isId: true }),
      ]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain("'GET', '/user'")
    expect(result).toContain("'POST', '/user'")
    expect(result).toContain("'PATCH', `/user/")
    expect(result).toContain("'DELETE', `/user/")
  })

  test('generates import statements for each model', () => {
    const models = [
      makeModel('User', [makeField({ name: 'id', type: 'Int', isId: true })]),
      makeModel('Post', [makeField({ name: 'id', type: 'Int', isId: true })]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain("import type { User, UserCreateInput, UserUpdateInput } from './User'")
    expect(result).toContain("import type { Post, PostCreateInput, PostUpdateInput } from './Post'")
  })

  test('generates methods for multiple models', () => {
    const models = [
      makeModel('User', [makeField({ name: 'id', type: 'Int', isId: true })]),
      makeModel('Post', [makeField({ name: 'id', type: 'Int', isId: true })]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain('async userFindMany()')
    expect(result).toContain('async postFindMany()')
  })

  test('uses string ID type when @id field is String', () => {
    const models = [
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true }),
      ]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain('async userFindUnique(id: string)')
  })

  test('handles models without @id by only generating findMany and create', () => {
    const models = [
      makeModel('Log', [
        makeField({ name: 'message', type: 'String' }),
        makeField({ name: 'level', type: 'String' }),
      ]),
    ]

    const result = generateClientClass(models, emptyEnums)

    expect(result).toContain('async logFindMany()')
    expect(result).toContain('async logCreate(data: LogCreateInput)')
    expect(result).not.toContain('logFindUnique')
    expect(result).not.toContain('logUpdate')
    expect(result).not.toContain('logDelete')
  })

  test('handles composite primary keys', () => {
    const model = {
      ...makeModel('PostTag', [
        makeField({ name: 'postId', type: 'Int' }),
        makeField({ name: 'tagId', type: 'Int' }),
      ]),
      primaryKey: { name: null, fields: ['postId', 'tagId'] },
    } as Model

    const result = generateClientClass([model], emptyEnums)

    expect(result).toContain('async postTagFindUnique(id: { postId: number; tagId: number })')
  })
})

