import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

const testDmmf: DMMF.Document = {
  datamodel: {
    models: [
      {
        name: 'User',
        dbName: null,
        schema: null,
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            type: 'Int',
            hasDefaultValue: true,
            default: { name: 'autoincrement', args: [] },
          },
          {
            kind: 'scalar',
            name: 'email',
            isRequired: true,
            isList: false,
            isUnique: true,
            isId: false,
            isReadOnly: false,
            type: 'String',
            hasDefaultValue: false,
          },
          {
            kind: 'scalar',
            name: 'name',
            isRequired: false,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'String',
            hasDefaultValue: false,
          },
          {
            kind: 'enum',
            name: 'role',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'UserRole',
            hasDefaultValue: true,
            default: 'USER',
          },
          {
            kind: 'object',
            name: 'posts',
            isRequired: false,
            isList: true,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'Post',
            hasDefaultValue: false,
            relationName: 'UserPosts',
            relationFromFields: [],
            relationToFields: [],
          },
        ],
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      },
      {
        name: 'Post',
        dbName: null,
        schema: null,
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            type: 'Int',
            hasDefaultValue: true,
            default: { name: 'autoincrement', args: [] },
          },
          {
            kind: 'scalar',
            name: 'title',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'String',
            hasDefaultValue: false,
          },
          {
            kind: 'scalar',
            name: 'published',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'Boolean',
            hasDefaultValue: true,
            default: false,
          },
          {
            kind: 'scalar',
            name: 'authorId',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: true,
            type: 'Int',
            hasDefaultValue: false,
          },
          {
            kind: 'object',
            name: 'author',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            type: 'User',
            hasDefaultValue: false,
            relationName: 'UserPosts',
            relationFromFields: ['authorId'],
            relationToFields: ['id'],
          },
        ],
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      },
    ],
    enums: [
      {
        name: 'UserRole',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
          { name: 'GUEST', dbName: null },
        ],
      },
    ],
    types: [],
    indexes: [],
  },
  schema: {
    inputObjectTypes: {},
    outputObjectTypes: { model: [], prisma: [] },
    enumTypes: { prisma: [] },
    fieldRefTypes: {},
  },
  mappings: {
    modelOperations: [],
    otherOperations: { read: [], write: [] },
  },
}

describe('generateRestClient', () => {
  let outputDir: string

  beforeEach(async () => {
    outputDir = await fs.mkdtemp(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  })

  afterEach(async () => {
    await fs.rm(outputDir, { recursive: true, force: true })
  })

  test('writes all expected files', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const files = await fs.readdir(outputDir)
    expect(files.sort()).toEqual(['Post.ts', 'User.ts', 'client.ts', 'enums.ts', 'index.ts'])
  })

  test('generated User.ts contains interface and input types', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'User.ts'), 'utf-8')

    expect(content).toContain('export interface User {')
    expect(content).toContain('  id: number')
    expect(content).toContain('  email: string')
    expect(content).toContain('  name: string | null')
    expect(content).toContain('  role: UserRole')
    expect(content).toContain('export interface UserCreateInput {')
    expect(content).toContain('export type UserUpdateInput = Partial<UserCreateInput>')

    // Relation fields excluded
    expect(content).not.toContain('posts')
  })

  test('generated User create input omits auto-generated fields', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'User.ts'), 'utf-8')
    const createSection = content.slice(content.indexOf('UserCreateInput'))

    // id is auto-increment, should be omitted
    expect(createSection).not.toMatch(/\bid:/)
  })

  test('generated Post.ts omits readOnly authorId from create input', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'Post.ts'), 'utf-8')
    const createSection = content.slice(content.indexOf('PostCreateInput'))

    // authorId is readOnly, should be omitted from create input
    expect(createSection).not.toContain('authorId')
  })

  test('generated enums.ts contains UserRole enum', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'enums.ts'), 'utf-8')

    expect(content).toContain('export enum UserRole {')
    expect(content).toContain("  ADMIN = 'ADMIN',")
    expect(content).toContain("  USER = 'USER',")
    expect(content).toContain("  GUEST = 'GUEST',")
  })

  test('generated client.ts contains RestApiClient with CRUD methods', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'client.ts'), 'utf-8')

    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('userFindMany')
    expect(content).toContain('userFindUnique')
    expect(content).toContain('userCreate')
    expect(content).toContain('userUpdate')
    expect(content).toContain('userDelete')
    expect(content).toContain('postFindMany')
    expect(content).toContain('postCreate')
  })

  test('generated index.ts re-exports everything', async () => {
    await generateRestClient({ dmmf: testDmmf, outputDir })

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(content).toContain("export * from './enums'")
    expect(content).toContain("export * from './User'")
    expect(content).toContain("export * from './Post'")
    expect(content).toContain("export * from './client'")
  })

  test('does not generate enums.ts when there are no enums', async () => {
    const noEnumDmmf = {
      ...testDmmf,
      datamodel: {
        ...testDmmf.datamodel,
        enums: [],
      },
    } as DMMF.Document

    await generateRestClient({ dmmf: noEnumDmmf, outputDir })

    const files = await fs.readdir(outputDir)
    expect(files).not.toContain('enums.ts')
  })
})

